<task_id>writer-v2-training-relu-004</task_id>
<specification>
At each in-range global x index, replace negative input values with zero and preserve non-negative values and store the result in results[settings.result_offset + index]. An invocation whose x index is at least settings.item_count must return before any storage access; output prefix and tail elements must remain untouched.
</specification>
<interface_contract>
{
  "entryPoint": "main",
  "stage": "compute",
  "requiredOverrides": [
    {
      "name": "WORKGROUP_SIZE",
      "type": "u32",
      "default": 32
    }
  ],
  "bindings": [
    {
      "group": 0,
      "binding": 0,
      "name": "values",
      "kind": "read_only_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 1,
      "name": "results",
      "kind": "read_write_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 2,
      "name": "settings",
      "kind": "uniform",
      "wgslType": "Settings"
    }
  ],
  "uniformLayout": [
    {
      "name": "item_count",
      "type": "u32",
      "byteOffset": 0
    },
    {
      "name": "result_offset",
      "type": "u32",
      "byteOffset": 4
    },
    {
      "name": "first_reserved",
      "type": "f32",
      "byteOffset": 8
    },
    {
      "name": "second_reserved",
      "type": "f32",
      "byteOffset": 12
    }
  ],
  "dispatch": "ceil(settings.item_count / WORKGROUP_SIZE) workgroups in x; y=1; z=1",
  "requiredBuiltin": "global_invocation_id",
  "boundsRule": "Return when global_invocation_id.x >= settings.item_count.",
  "outputRule": "Write only results[settings.result_offset + index]."
}
</interface_contract>

completion:
override WORKGROUP_SIZE: u32 = 32u;

struct Settings {
    item_count: u32,
    result_offset: u32,
    first_reserved: f32,
    second_reserved: f32,
}

@group(0) @binding(0) var<storage, read> values: array<f32>;
@group(0) @binding(1) var<storage, read_write> results: array<f32>;
@group(0) @binding(2) var<uniform> settings: Settings;

@compute @workgroup_size(WORKGROUP_SIZE, 1, 1)
fn main(@builtin(global_invocation_id) global_invocation: vec3<u32>) {
    let logical_index = global_invocation.x;
