Return only the complete WGSL source; no Markdown fence, diff, or explanation.
The shader must implement every binding, entry-point, dispatch, bounds, and arithmetic requirement exactly.
<task_id>writer-v2-training-relu-038</task_id>
<specification>
For every logical index, replace negative input values with zero and preserve non-negative values, then store the result in destination[kernel_params.destination_start + index]. An invocation whose x index is at least kernel_params.num_elements must return before any storage access.
</specification>
<interface_contract>
{
  "entryPoint": "main",
  "stage": "compute",
  "requiredOverrides": [
    {
      "name": "WORKGROUP_SIZE",
      "type": "u32",
      "default": 128
    }
  ],
  "bindings": [
    {
      "group": 0,
      "binding": 0,
      "name": "source",
      "kind": "read_only_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 1,
      "name": "destination",
      "kind": "read_write_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 2,
      "name": "kernel_params",
      "kind": "uniform",
      "wgslType": "KernelParams"
    }
  ],
  "uniformLayout": [
    {
      "name": "num_elements",
      "type": "u32",
      "byteOffset": 0
    },
    {
      "name": "destination_start",
      "type": "u32",
      "byteOffset": 4
    },
    {
      "name": "first_reserved",
      "type": "f32",
      "byteOffset": 8
    },
    {
      "name": "second_reserved",
      "type": "f32",
      "byteOffset": 12
    }
  ],
  "dispatch": "ceil(kernel_params.num_elements / WORKGROUP_SIZE) workgroups in x; y=1; z=1",
  "requiredBuiltin": "global_invocation_id",
  "boundsRule": "Return when global_invocation_id.x >= kernel_params.num_elements.",
  "outputRule": "Write only destination[kernel_params.destination_start + index]."
}
</interface_contract>

completion:
override WORKGROUP_SIZE: u32 = 128u;

struct KernelParams {
    num_elements: u32,
    destination_start: u32,
    first_reserved: f32,
    second_reserved: f32,
}

@group(0) @binding(0) var<storage, read> source: array<f32>;
@group(0) @binding(1) var<storage, read_write> destination: array<f32>;
@group(0) @binding(2) var<uniform> kernel_params: KernelParams;

@compute @workgroup_size(WORKGROUP_SIZE, 1, 1)
fn main(@builtin(global_invocation_id) invocation: vec3<u32>) {
    let linear_index = invocation.x;
    if (linear_index >= kernel_params.num_elements) {
        return;
    }

    let computed = max(source[linear_index], 0.0);
    destination[kernel_params.destination_start + linear_index] = computed;
}

